import React from "react";

import {
  Cloud,
  Sprout,
  ShoppingBag,
  Building2,
  TrendingUp,
  Phone,
  ArrowRight,
} from "lucide-react";

import "./Dashboard.css";

export default function Dashboard({ setActivePage }) {

  const weather = [
    { day: "Today", temp: "31°C", rain: "20%" },
    { day: "Tomorrow", temp: "30°C", rain: "40%" },
    { day: "Monday", temp: "33°C", rain: "10%" },
  ];

  const marketPrices = [
    {
      crop: "Rice",
      price: "₹2800",
      change: "+2%"
    },

    {
      crop: "Tomato",
      price: "₹32",
      change: "-1%"
    },

    {
      crop: "Cotton",
      price: "₹7600",
      change: "+3%"
    },

    {
      crop: "Onion",
      price: "₹28",
      change: "+1%"
    },
  ];

  const schemes = [
    "PM Kisan Samman Nidhi",

    "PM Fasal Bima Yojana",

    "PM Krishi Sinchai",

    "Kisan Credit Card",
  ];

  const quickActions = [
    {
      icon: Cloud,
      title: "Weather",
    },

    {
      icon: Sprout,
      title: "Crop Advisor",
    },

    {
      icon: ShoppingBag,
      title: "Market Prices",
    },

    {
      icon: Building2,
      title: "Government Schemes",
    },
  ];

  return (
    <div className="dashboard-main">

      {/* Hero */}

      <div className="hero-banner">

        <div className="hero-overlay">

          <h1 className="hero-title">

            🌾 Welcome Farmer

          </h1>

          <p className="hero-sub">

            Digital Agriculture Support Portal

          </p>

          <div className="hero-actions">

            <button
              className="btn-primary"
              onClick={() =>
                setActivePage("Weather")
              }
            >

              View Weather

            </button>

            <button
              className="btn-secondary"
              onClick={() =>
                setActivePage("Government Schemes")
              }
            >

              Schemes

            </button>

          </div>

        </div>

      </div>

      {/* Statistics */}

      <div className="stats-row">

        <div className="stat-card">

          <div>

            <h3>31°C</h3>

            <p>Weather</p>

          </div>

        </div>

        <div className="stat-card">

          <div>

            <h3>₹7600</h3>

            <p>Cotton Price</p>

          </div>

        </div>

        <div className="stat-card">

          <div>

            <h3>4</h3>

            <p>Government Schemes</p>

          </div>

        </div>

        <div className="stat-card">

          <div>

            <h3>3</h3>

            <p>Tasks Today</p>

          </div>

        </div>

      </div>

      {/* Quick Actions */}

      <div className="dashboard-card">

        <h2>

          Quick Actions

        </h2>

        <div className="quick-grid">

          {quickActions.map((item) => {

            const Icon = item.icon;

            return (

              <button

                key={item.title}

                className="quick-btn"

                onClick={() =>
                  setActivePage(item.title)
                }

              >

                <Icon size={24} />

                <span>

                  {item.title}

                </span>

              </button>

            );

          })}

        </div>

      </div>

      {/* Weather */}

      <div className="dashboard-card">

        <h2>

          Weather Forecast

        </h2>

        {weather.map((item) => (

          <div
            className="list-row"
            key={item.day}
          >

            <div>

              {item.day}

            </div>

            <div>

              {item.temp}

            </div>

            <div>

              Rain {item.rain}

            </div>

          </div>

        ))}

      </div>

      {/* Market Prices */}

      <div className="dashboard-card">

        <h2>

          Market Prices

        </h2>

        {marketPrices.map((item) => (

          <div
            className="list-row"
            key={item.crop}
          >

            <div>

              {item.crop}

            </div>

            <div>

              {item.price}

            </div>

            <div>

              {item.change}

            </div>

          </div>

        ))}

      </div>

      {/* Government Schemes */}

      <div className="dashboard-card">

        <h2>

          Government Schemes

        </h2>

        {schemes.map((item) => (

          <div
            className="scheme-row"
            key={item}
          >

            {item}

          </div>

        ))}

      </div>

      {/* Emergency */}

      <div className="dashboard-card">

        <h2>

          Help Center

        </h2>

        <div className="help-box">

          <Phone size={18} />

          <span>

            Farmer Helpline : 1800-180-1551

          </span>

        </div>

      </div>

      {/* Footer */}

      <div className="dashboard-card">

        <button
          className="view-btn"
          onClick={() =>
            setActivePage("Reports")
          }
        >

          View Reports

          <ArrowRight size={18} />

        </button>

      </div>

    </div>
  );
}
